import{_ as o,o as i,c as a,a2 as r}from"./chunks/framework.ac-V-Xu_.js";const m=JSON.parse('{"title":"Risoluzione problemi","description":"","frontmatter":{},"headers":[],"relativePath":"it/risoluzione-problemi.md","filePath":"it/risoluzione-problemi.md"}'),t={name:"it/risoluzione-problemi.md"};function l(n,e,s,d,c,u){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="risoluzione-problemi" tabindex="-1">Risoluzione problemi <a class="header-anchor" href="#risoluzione-problemi" aria-label="Permalink to &quot;Risoluzione problemi&quot;">​</a></h1><p>Problemi comuni e soluzioni.</p><h2 id="problemi-di-configurazione" tabindex="-1">Problemi di configurazione <a class="header-anchor" href="#problemi-di-configurazione" aria-label="Permalink to &quot;Problemi di configurazione&quot;">​</a></h2><h3 id="api-key-is-required" tabindex="-1">&quot;API key is required&quot; <a class="header-anchor" href="#api-key-is-required" aria-label="Permalink to &quot;&quot;API key is required&quot;&quot;">​</a></h3><p>Assicurati di avere una chiave API OpenRouter valida. Esegui <code>/setup</code> per reinserirla.</p><p>Ottieni una chiave su <a href="https://openrouter.ai" target="_blank" rel="noreferrer">openrouter.ai</a>.</p><h3 id="model-not-found" tabindex="-1">&quot;Model not found&quot; <a class="header-anchor" href="#model-not-found" aria-label="Permalink to &quot;&quot;Model not found&quot;&quot;">​</a></h3><p>L&#39;ID del modello deve corrispondere al formato di OpenRouter: <code>provider/model-name</code>. Usa <code>/model</code> per sfogliare i modelli disponibili.</p><h2 id="problemi-con-gli-agenti" tabindex="-1">Problemi con gli agenti <a class="header-anchor" href="#problemi-con-gli-agenti" aria-label="Permalink to &quot;Problemi con gli agenti&quot;">​</a></h2><h3 id="l-agente-non-compare-nella-lista-agent" tabindex="-1">L&#39;agente non compare nella lista /agent <a class="header-anchor" href="#l-agente-non-compare-nella-lista-agent" aria-label="Permalink to &quot;L&#39;agente non compare nella lista /agent&quot;">​</a></h3><ul><li>Verifica che il file sia in <code>.turbodev/agents/</code> (progetto) o <code>~/.config/turbodev/agents/</code> (globale)</li><li>Assicurati che il nome del file termini con <code>.md</code></li><li>Verifica che <code>disable: true</code> non sia impostato</li><li>Riavvia TurboDev dopo aver aggiunto nuovi file agente</li></ul><h3 id="l-agente-personalizzato-non-sovrascrive-quello-predefinito" tabindex="-1">L&#39;agente personalizzato non sovrascrive quello predefinito <a class="header-anchor" href="#l-agente-personalizzato-non-sovrascrive-quello-predefinito" aria-label="Permalink to &quot;L&#39;agente personalizzato non sovrascrive quello predefinito&quot;">​</a></h3><p>Il merge è <strong>superficiale</strong> — solo i campi specificati vengono sovrascritti. Assicurati che il nome del file corrisponda esattamente al nome predefinito (es. <code>editor.md</code> per sovrascrivere l&#39;agente editor).</p><h3 id="il-prompt-di-permesso-non-appare" tabindex="-1">Il prompt di permesso non appare <a class="header-anchor" href="#il-prompt-di-permesso-non-appare" aria-label="Permalink to &quot;Il prompt di permesso non appare&quot;">​</a></h3><ul><li>Verifica che l&#39;agente abbia <code>permission: edit: ask</code> (non <code>allow</code>)</li><li>Controlla che lo strumento non sia disabilitato tramite <code>tools: edit_file: false</code> (gli strumenti disabilitati restituiscono subito un errore, nessun prompt)</li></ul><h2 id="problemi-con-gli-strumenti" tabindex="-1">Problemi con gli strumenti <a class="header-anchor" href="#problemi-con-gli-strumenti" aria-label="Permalink to &quot;Problemi con gli strumenti&quot;">​</a></h2><h3 id="errore-not-found-con-edit-file" tabindex="-1">Errore &quot;not found&quot; con edit_file <a class="header-anchor" href="#errore-not-found-con-edit-file" aria-label="Permalink to &quot;Errore &quot;not found&quot; con edit_file&quot;">​</a></h3><p><code>old_str</code> deve corrispondere <strong>esattamente</strong> — inclusi spazi bianchi e indentazione. Copia il testo esatto dal file.</p><h3 id="timeout-del-comando-bash" tabindex="-1">Timeout del comando bash <a class="header-anchor" href="#timeout-del-comando-bash" aria-label="Permalink to &quot;Timeout del comando bash&quot;">​</a></h3><p>Aumenta il timeout nel comando:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bash({ &quot;command&quot;: &quot;npm test&quot;, &quot;timeout&quot;: 60000 })</span></span></code></pre></div><h2 id="problemi-con-agents-md" tabindex="-1">Problemi con AGENTS.md <a class="header-anchor" href="#problemi-con-agents-md" aria-label="Permalink to &quot;Problemi con AGENTS.md&quot;">​</a></h2><h3 id="agents-md-non-rilevato-all-avvio" tabindex="-1">AGENTS.md non rilevato all&#39;avvio <a class="header-anchor" href="#agents-md-non-rilevato-all-avvio" aria-label="Permalink to &quot;AGENTS.md non rilevato all&#39;avvio&quot;">​</a></h3><ul><li>Il file deve trovarsi nella <strong>directory di lavoro corrente</strong> dove hai avviato TurboDev</li><li>Il nome del file deve essere esattamente <code>AGENTS.md</code> (maiuscolo)</li><li>Se lo crei durante una sessione con <code>/init</code>, viene caricato immediatamente</li></ul><h3 id="init-non-rileva-il-tipo-di-progetto" tabindex="-1">/init non rileva il tipo di progetto <a class="header-anchor" href="#init-non-rileva-il-tipo-di-progetto" aria-label="Permalink to &quot;/init non rileva il tipo di progetto&quot;">​</a></h3><p>Il rilevamento del progetto cerca:</p><ul><li><strong>Node.js</strong>: <code>package.json</code></li><li><strong>Python</strong>: <code>pyproject.toml</code> o <code>requirements.txt</code></li><li><strong>Rust</strong>: <code>Cargo.toml</code></li><li><strong>Go</strong>: <code>go.mod</code></li></ul><h2 id="problemi-generali" tabindex="-1">Problemi generali <a class="header-anchor" href="#problemi-generali" aria-label="Permalink to &quot;Problemi generali&quot;">​</a></h2><h3 id="l-ai-si-blocca-o-ci-mette-troppo" tabindex="-1">L&#39;AI si blocca o ci mette troppo <a class="header-anchor" href="#l-ai-si-blocca-o-ci-mette-troppo" aria-label="Permalink to &quot;L&#39;AI si blocca o ci mette troppo&quot;">​</a></h3><p>Premi <strong>Escape</strong> per cancellare la richiesta corrente. La barra di input riapparirà e potrai riprovare o riformulare il messaggio.</p><p>Se il problema persiste:</p><ul><li>Il modello potrebbe star generando una risposta molto lunga — prova un modello più veloce</li><li>La finestra di contesto potrebbe essere piena — usa <code>/compact</code> per riassumere la conversazione</li><li>Verifica la connessione di rete a OpenRouter</li></ul><h3 id="messaggio-request-cancelled" tabindex="-1">Messaggio &quot;Request cancelled&quot; <a class="header-anchor" href="#messaggio-request-cancelled" aria-label="Permalink to &quot;Messaggio &quot;Request cancelled&quot;&quot;">​</a></h3><p>Se vedi <code>Request cancelled. You can try sending your message again.</code> — tu (o un timeout) hai interrotto la richiesta. Invia semplicemente di nuovo il messaggio.</p><h3 id="turbodev-e-lento" tabindex="-1">TurboDev è lento <a class="header-anchor" href="#turbodev-e-lento" aria-label="Permalink to &quot;TurboDev è lento&quot;">​</a></h3><ul><li>Prova un modello più veloce (es. <code>anthropic/claude-haiku-4-20250514</code>)</li><li>Usa l&#39;agente plan per analisi rapide senza modifiche</li><li>Riduci <code>steps</code> nella configurazione dell&#39;agente per limitare le iterazioni</li></ul><h3 id="schermo-vuoto-o-sfarfallio" tabindex="-1">Schermo vuoto o sfarfallio <a class="header-anchor" href="#schermo-vuoto-o-sfarfallio" aria-label="Permalink to &quot;Schermo vuoto o sfarfallio&quot;">​</a></h3><p>Assicurati di usare un emulatore di terminale moderno. Consigliati:</p><ul><li><a href="https://wezterm.org" target="_blank" rel="noreferrer">WezTerm</a></li><li><a href="https://alacritty.org" target="_blank" rel="noreferrer">Alacritty</a></li><li><a href="https://sw.kovidgoyal.net/kitty/" target="_blank" rel="noreferrer">Kitty</a></li><li><a href="https://iterm2.com" target="_blank" rel="noreferrer">iTerm2</a> (macOS)</li></ul>',39)])])}const h=o(t,[["render",l]]);export{m as __pageData,h as default};
